<script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import BottomNav from '../../components/BottomNav.vue';import ServiceIcon from '../../components/ServiceIcon.vue';import VisitCard from '../../components/VisitCard.vue';import{registrationApi}from'../../api/registration';const quick=[['电子病历','/pages/records/index','compose','blue'],['检查报告','/pages/records/index?tab=report','search','blue'],['处方记录','/pages/prescription/index','list','green'],['门诊缴费','/pages/payment/index','wallet-filled','orange'],['AI预问诊','/pages/previsit/index','chat-filled','purple'],['随访管理','/pages/followup/index','notification-filled','orange']];const visits=ref<Array<{status:string;department:string;doctor:string;date:string;time:string;location?:string;patient?:string}>>([]),loading=ref(false);function open(path:string){uni.navigateTo({url:path})}async function load(){loading.value=true;try{const data=await registrationApi.managed();visits.value=data.map(item=>({status:item.payStatus===0?'待缴费':item.statusName||'待就诊',department:item.departmentName||'门诊科室',doctor:item.physicianName||'待分配医生',date:item.visitDate||'',time:item.visitTime||'',patient:item.patientName||'张三'}))}finally{loading.value=false}}onShow(load)</script>
<template><view class="page-shell"><view class="page-title">我的就诊</view><view class="page-subtitle">挂号、病历、报告与缴费都在这里</view><view class="quick card"><view v-for="item in quick" :key="item[0]" @tap="open(item[1])"><view class="quick-icon-platform"><ServiceIcon :type="item[2]" :tone="item[3]"/></view><text>{{item[0]}}</text></view></view><view class="tabs card"><text class="active">全部挂号</text><text>待就诊</text><text>已完成</text></view><view v-if="loading" class="state">正在加载挂号记录…</view><VisitCard v-for="item in visits" :key="item.department+item.date" :visit="item" @action="item.status==='待缴费'?open('/pages/payment/index'):open('/pages/records/index')"/><view v-if="!loading&&!visits.length" class="state card">暂无挂号记录</view><BottomNav :active="1"/></view></template>
<style scoped lang="scss">.quick{margin-top:28rpx;padding:26rpx 10rpx;display:grid;grid-template-columns:repeat(4,1fr)}.quick>view{display:flex;flex-direction:column;align-items:center;gap:12rpx;font-size:22rpx}.quick-icon-platform{padding:7rpx;border-radius:23rpx;background:#f5f8fd;border:1rpx solid #edf2f8}.state{margin-top:20rpx;padding:45rpx;text-align:center;color:#8d98aa;font-size:21rpx}.tabs{margin-top:22rpx;display:flex}.tabs text{flex:1;padding:27rpx;text-align:center;color:#758098}.tabs .active{color:#2878ff;border-bottom:5rpx solid #2878ff}.visit{margin-top:20rpx;padding:24rpx}.visit-head,.visit-foot{display:flex;justify-content:space-between;color:#7c889d;font-size:20rpx}.visit-head text:first-child{color:#13a67c}.visit-body{display:grid;grid-template-columns:75rpx 1fr 1fr;gap:15rpx;align-items:center;padding:25rpx 0;border-bottom:1rpx solid #edf0f5}.visit-body>view{display:flex;flex-direction:column;gap:10rpx;color:#77849a;font-size:21rpx}.round{width:68rpx;height:68rpx;border-radius:50%;display:flex!important;align-items:center;justify-content:center;background:linear-gradient(145deg,#71c5ff,#276dff);color:#fff;font-size:36rpx}.dept,.date{color:#10204c;font-size:25rpx;font-weight:650}.visit-foot{align-items:center;padding-top:17rpx}.visit-foot button{margin:0;background:#2878ff;color:#fff}</style>
